import{c as t,Q as a,j as i,m as o}from"./chunks/framework.BA1dEi98.js";const u=JSON.parse('{"title":"Data Hygiene","description":"","frontmatter":{},"headers":[],"relativePath":"guide/using-librislog/data-hygiene.md","filePath":"guide/using-librislog/data-hygiene.md","lastUpdated":1780263809000}'),s={name:"guide/using-librislog/data-hygiene.md"};function r(l,e,n,h,d,c){return a(),i("div",null,[...e[0]||(e[0]=[o('<h1 id="data-hygiene" tabindex="-1">Data Hygiene <a class="header-anchor" href="#data-hygiene" aria-label="Permalink to &quot;Data Hygiene&quot;">​</a></h1><p>The Data Hygiene page helps you find and fix books with missing metadata. It&#39;s accessible from your <strong>Profile → Manage my data → Data Hygiene</strong>.</p><h2 id="attribute-filtering" tabindex="-1">Attribute Filtering <a class="header-anchor" href="#attribute-filtering" aria-label="Permalink to &quot;Attribute Filtering&quot;">​</a></h2><p>The page lists books that are missing one or more of the tracked attributes. Use the chip buttons at the top to filter by specific attributes:</p><ul><li><strong>Single attribute</strong>: Click a chip to show only books missing that specific field</li><li><strong>Multiple attributes</strong>: Click several chips to narrow down further</li><li><strong>Match mode</strong>: Toggle between &quot;Match any&quot; (OR logic — book missing any selected attribute) and &quot;Match all&quot; (AND logic — book must miss all selected attributes)</li><li><strong>Default view</strong>: With no chips selected, all books missing at least one tracked attribute are shown</li></ul><p>Tracked attributes: title, author, ISBN, publisher, published year, blurb, language, subtitle, page count, and cover.</p><h2 id="reviewing-missing-data" tabindex="-1">Reviewing Missing Data <a class="header-anchor" href="#reviewing-missing-data" aria-label="Permalink to &quot;Reviewing Missing Data&quot;">​</a></h2><p>Each row in the table shows:</p><ul><li>Book title, author, ISBN, and publisher</li><li>A &quot;Missing&quot; column with badges for each missing attribute</li></ul><p>Select individual books or use the checkbox in the header to select all visible books. The action bar at the bottom appears once at least one book is selected.</p><h2 id="batch-editing" tabindex="-1">Batch Editing <a class="header-anchor" href="#batch-editing" aria-label="Permalink to &quot;Batch Editing&quot;">​</a></h2><p>The batch action bar lets you update multiple books at once:</p><ol><li><strong>Select books</strong> using the checkboxes</li><li><strong>Pick a field</strong> from the dropdown (only attributes that are missing in the selected books appear)</li><li><strong>Enter a value</strong> — text fields get a text input, numeric fields (page count, year) get a number input</li><li><strong>Click &quot;Apply to selected&quot;</strong> to open a confirmation dialog showing a preview of affected books</li><li><strong>Confirm</strong> to apply the change</li></ol><h3 id="cover-url" tabindex="-1">Cover URL <a class="header-anchor" href="#cover-url" aria-label="Permalink to &quot;Cover URL&quot;">​</a></h3><p>When setting <code>cover_url</code>, the app validates the URL, downloads the image, and stores it locally. If the download fails, that book is skipped and reported in the result summary.</p><h3 id="language" tabindex="-1">Language <a class="header-anchor" href="#language" aria-label="Permalink to &quot;Language&quot;">​</a></h3><p>Language values are normalized to uppercase; invalid ISO codes are rejected.</p><h3 id="published-year" tabindex="-1">Published Year <a class="header-anchor" href="#published-year" aria-label="Permalink to &quot;Published Year&quot;">​</a></h3><p>No lower bound is enforced, so ancient or religious texts (e.g., the Bible) can be entered with years before 1000.</p><h2 id="success-error-states" tabindex="-1">Success &amp; Error States <a class="header-anchor" href="#success-error-states" aria-label="Permalink to &quot;Success &amp; Error States&quot;">​</a></h2><ul><li><strong>All complete</strong>: When no books are missing data, a green success message appears</li><li><strong>Filtered complete</strong>: When specific attributes are selected and all books have them, a tailored success message is shown</li><li><strong>Errors</strong>: API errors are displayed in an alert banner; dismiss it to try again</li></ul><h2 id="see-also" tabindex="-1">See Also <a class="header-anchor" href="#see-also" aria-label="Permalink to &quot;See Also&quot;">​</a></h2><ul><li><a href="/librislog/next/guide/using-librislog/missing-covers.html">Missing Covers Workflow</a> — dedicated one-at-a-time workflow for assigning book covers</li></ul>',23)])])}const b=t(s,[["render",r]]);export{u as __pageData,b as default};
